import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/currencies"
	entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
	"github.com/openmeterio/openmeter/pkg/models"
)

func (a *adapter) UpdateCurrency(ctx context.Context, params currencies.UpdateCurrencyInput) (currencies.Currency, error) {
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (currencies.Currency, error) {
		curr, err := tx.db.CustomCurrency.UpdateOneID(params.ID).
			SetName(params.Name).
			Save(ctx)
		if err != nil {
			if entdb.IsConstraintError(err) {
				return currencies.Currency{}, models.NewGenericConflictError(fmt.Errorf("conflict: %w", err))
			}
			return currencies.Currency{}, fmt.Errorf("update currency: %w", err)
		}
		return mapCurrencyFromDB(curr), nil
	})
}

import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/currencies"
	"github.com/openmeterio/openmeter/pkg/framework/transaction"
	"github.com/openmeterio/openmeter/pkg/models"
)

func (s *Service) DeleteCurrency(ctx context.Context, params currencies.DeleteCurrencyInput) error {
	if params.Validate() != nil {
		return models.NewGenericValidationError(fmt.Errorf("invalid input: %w", params.Validate()))
	}
	_, err := transaction.Run(ctx, s.adapter, func(ctx context.Context) (struct{}, error) {
		return struct{}{}, s.adapter.DeleteCurrency(ctx, params)
	})
	return err
}
